return [
  {
    json: {
      item_id: '6d6e2f96ab2c',
      source_type: 'rss',
      source_name: 'OpenAI YouTube',
      canonical_url: 'https://example.com/post',
      title: 'Example normalized item',
      author: 'OpenAI',
      published_at: '2026-04-17T09:00:00-04:00',
      ingested_at: '2026-04-17T09:05:00-04:00',
      media_type: 'text',
      content_text: 'Normalized plain text content for scoring and summary.',
      content_hash: 'sha256:example',
      tags: ['inbox', 'ai-information-processor'],
      dedupe_action: 'full_push',
      status: 'raw'
    }
  }
];

const systemPrompt = [
  'You are the enrichment layer of AIInformationProcessor.',
  'Return JSON only.',
  'The JSON schema must be: {"score": number, "category": string, "tags": string[], "summary": string, "reason": string}.',
  'Use content_text as the only source of truth for analysis.'
].join('\n');

return {
  json: {
    ...$json,
    llm_request: {
      model: $env.LLM_MODEL || 'set-in-env',
      response_format: 'json_object',
      system_prompt: systemPrompt,
      user_payload: {
        title: $json.title,
        source_name: $json.source_name,
        content_text: $json.content_text
      }
    }
  }
};

const enrichment = {
  score: 0.82,
  category: 'AI Infra',
  tags: ['openai', 'model-release'],
  summary: 'Example final summary produced by the main enrichment layer.',
  reason: 'Example reason showing why the item is worth keeping.'
};

return {
  json: {
    ...$json,
    ...enrichment,
    tags: [...new Set([...(Array.isArray($json.tags) ? $json.tags : []), ...enrichment.tags])],
    status: 'enriched'
  }
};
